/**
 * Fetches user data by ID.
 * @param {number} userId - The ID of the user to fetch.
 * @returns {Promise<{id: number, name: string}>} A promise that resolves with the user object.
 */
function fetchUserDataAsync(userId) {
    return new Promise((resolve, reject) => {
        setTimeout(() => {
            if (userId < 0) {
                reject(new Error("Invalid user ID"));
            } else {
                resolve({ id: userId, name: `User${userId}` });
            }
        }, 100);
    });
}

/**
 * Saves user data.
 * @param {Object} userData - The user data to save.
 * @param {number} userData.id - The ID of the user.
 * @param {string} userData.name - The name of the user.
 * @returns {Promise<{success: boolean, id: number}>} A promise that resolves with the success status and user ID.
 */
function saveUserDataAsync(userData) {
    return new Promise((resolve, reject) => {
        setTimeout(() => {
            if (!userData.name) {
                reject(new Error("Name is required"));
            } else {
                resolve({ success: true, id: userData.id });
            }
        }, 100);
    });
}
```

