    }

    override fun flush() {
        super.flush()
        secondaryStream.flush()
    }

    override fun close() {
        try {
            super.close()
        } finally {
            secondaryStream.close()
        }
    }
}

internal fun OutputStream.alsoOutputTo(secondaryStream: OutputStream): OutputStream =
    MultiOutputStream(this, secondaryStream)

