                nthChild(Nth.Odd) style {
                    color(Color.green)
                }
            }
        }

        assertContentEquals(
            listOf(".someClass { color: red;}", ".someClass :nth-child(odd) { color: green;}"),
            styleSheet.serializeRules()
        )
    }

